import java.util.*;
class StringIterator {
    String s;
    int i;
    int count;
    char ch;

    public StringIterator(String compressedString) {
        s = compressedString;
        i = 0;
        count = 0;
        ch = ' ';
    }

    public char next() {
        if(!hasNext()) {
            return ' ';
        }
        if(count == 0) {
            ch = s.charAt(i++);
            while(i < s.length() && Character.isDigit(s.charAt(i))) {
                count = count * 10 + (s.charAt(i++) - '0');
            }
        }
        count--;
        return ch;
    }

    public boolean hasNext() {
        return i < s.length() || count != 0;
    }
}
